def do_algebra(operator, operand):
    # Initialize the result with the first operand
    result = operand[0]

    # Iterate over the operators and operands
    for i in range(len(operator)):
        # Perform the operation
        if operator[i] == '+':
            result += operand[i+1]
        elif operator[i] == '-':
            result -= operand[i+1]
        elif operator[i] == '*':
            result *= operand[i+1]
        elif operator[i] == '//':
            result //= operand[i+1]
        elif operator[i] == '**':
            result **= operand[i+1]

    # Return the result
    return result

