import heapq

def find_minimum_range(arrays):
    min_heap = []
    max_val = float('-inf')
    min_range = float('inf')
    min_range_start = float('-inf')
    min_range_end = float('inf')
    hash_map = {}

    for i in range(len(arrays)):
        for j in range(len(arrays[i])):
            heapq.heappush(min_heap, (arrays[i][j], i))
            max_val = max(max_val, arrays[i][j])
            hash_map[i] = hash_map.get(i, 0) + 1

            while len(min_heap) == len(arrays):
                if max_val - min_heap[0][0] < min_range:
                    min_range = max_val - min_heap[0][0]
                    min_range_start = min_heap[0][0]
                    min_range_end = max_val

                hash_map[min_heap[0][1]] -= 1
                if hash_map[min_heap[0][1]] == 0:
                    del hash_map[min_heap[0][1]]
                heapq.heappop(min_heap)

    return (min_range_start, min_range_end)

