def is_subset_sum(arr, n, sum):
    # The value of subset[i][j] will be true if there is a
    # subset of arr[0..j-1] with sum equal to i
    subset = [[False for i in range(sum + 1)] for j in range(n + 1)]

    # If sum is 0, then answer is true
    for i in range(n + 1):
        subset[i][0] = True

    # If sum is not 0 and arr is empty, then answer is false
    for i in range(1, sum + 1):
        subset[0][i] = False

    # Fill the subset table in bottom up manner
    for i in range(1, n + 1):
        for j in range(1, sum + 1):
            if j < arr[i-1]:
                subset[i][j] = subset[i-1][j]
            if j >= arr[i-1]:
                subset[i][j] = (subset[i-1][j] or subset[i-1][j-arr[i-1]])

    # return the last entry of the table
    return subset[n][sum]

