import heapq

def rearange_string(s):
    count = {}
    for c in s:
        count[c] = count.get(c, 0) + 1
    heap = [(-v, k) for k, v in count.items()]
    heapq.heapify(heap)
    res = []
    while len(heap) > 1:
        c1, k1 = heapq.heappop(heap)
        c2, k2 = heapq.heappop(heap)
        res.append(k1)
        res.append(k2)
        if c1 + 1 < 0:
            heapq.heappush(heap, (c1 + 1, k1))
        if c2 + 1 < 0:
            heapq.heappush(heap, (c2 + 1, k2))
    if heap:
        c, k = heapq.heappop(heap)
        if c < -1:
            return ''
        res.append(k)
    return ''.join(res)

def solution(a, b, n):
    def extended_gcd(a, b):
        if a == 0:
            return b, 0, 1
        else:
            gcd, x, y = extended_gcd(b % a, a)
            return gcd, y - (b // a) * x, x

    gcd, x, y = extended_gcd(a, b)
    if n % gcd != 0:
        return 'No solution'
    else:
        return ('x = ', n // gcd * x, ', y = ', n // gcd * y)

