    # Initialize a 2D array to store the maximum gold we can get for each cell
    dp = [[0 for _ in range(n)] for _ in range(m)]

    # For each cell in the first column, the maximum gold we can get is the gold in the cell itself
    for i in range(m):
        dp[i][0] = grid[i][0]

    # For each cell in the remaining columns, calculate the maximum gold we can get
    for j in range(1, n):
        for i in range(m):
            # Calculate the maximum gold we can get by moving to the right, right-up, or right-down
            right = dp[i][j-1]
            right_up = dp[i-1][j-1] if i > 0 else 0
            right_down = dp[i+1][j-1] if i < m-1 else 0
            dp[i][j] = grid[i][j] + max(right, right_up, right_down)

    # Return the maximum gold we can get from the last column
    return max(dp[i][n-1] for i in range(m))

