def longest_common_subsequence(X, Y, m, n):
    # Create a table to store lengths of longest common subsequence
    # of substrings of X[0..i-1] and Y[0..j-1]
    L = [[0 for k in range(n+1)] for l in range(m+1)]

    # Build L[m+1][n+1] in bottom up fashion
    for i in range(m+1):
        for j in range(n+1):
            if i == 0 or j == 0:
                L[i][j] = 0
            elif X[i-1] == Y[j-1]:
                L[i][j] = L[i-1][j-1] + 1
            else:
                L[i][j] = max(L[i-1][j], L[i][j-1])

    # L[m][n] contains the length of LCS of X[0..n-1] and Y[0..m-1]
    return L[m][n]

